async function analyzePriceTrend(materialId, startDate, endDate) {
  const db2 = await getDb();
  if (!db2) throw new Error("Database connection failed");
  const materialQuery = sql53`
    SELECT id, material_code, material_name, unit_price
    FROM h_materials
    WHERE id = ${materialId}
  `;
  const materialResult = await db2.execute(materialQuery);
  if (!materialResult || materialResult.length === 0) {
    return null;
  }
  const material = materialResult[0];
  const priceHistoryQuery = sql53`
    SELECT new_price, changed_at
    FROM h_material_price_history
    WHERE material_id = ${materialId}
      AND changed_at >= ${startDate}
      AND changed_at <= ${endDate}
    ORDER BY changed_at ASC
  `;
  const priceHistory = await db2.execute(priceHistoryQuery);
  const priceChanges = (priceHistory || []).map((row) => ({
    price: Number(row.new_price),
    date: new Date(row.changed_at)
  }));
  const prices = priceChanges.map((pc) => pc.price);
  const avgPrice = prices.length > 0 ? prices.reduce((a, b) => a + b, 0) / prices.length : 0;
  const minPrice = prices.length > 0 ? Math.min(...prices) : 0;
  const maxPrice = prices.length > 0 ? Math.max(...prices) : 0;
  let trend = "stable";
  if (prices.length >= 2) {
    const firstHalf = prices.slice(0, Math.floor(prices.length / 2));
    const secondHalf = prices.slice(Math.floor(prices.length / 2));
    const avgFirst = firstHalf.reduce((a, b) => a + b, 0) / firstHalf.length;
    const avgSecond = secondHalf.reduce((a, b) => a + b, 0) / secondHalf.length;
    if (avgSecond > avgFirst * 1.1) trend = "increasing";
    else if (avgSecond < avgFirst * 0.9) trend = "decreasing";
  }
  return {
    materialId,
    materialCode: material.material_code,
    materialName: material.material_name,
    currentPrice: Number(material.unit_price),
    avgPrice,
    minPrice,
    maxPrice,
    priceChanges,
    trend
  };
}
