async function calculateProductionPriority() {
  const db2 = await getDb();
  if (!db2) throw new Error("Database not available");
  const lowStockProducts = await db2.select({
    productId: hInventoryLots.productId,
    totalQuantity: sql54`SUM(${hInventoryLots.availableQuantity})`
  }).from(hInventoryLots).where(eq91(hInventoryLots.status, "available")).groupBy(hInventoryLots.productId);
  return lowStockProducts.map((product) => ({
    productId: product.productId,
    currentStock: parseFloat(product.totalQuantity || "0"),
    priority: calculatePriority(parseFloat(product.totalQuantity || "0"), 100)
    // 기본 안전 재고 100
  }));
}
function calculatePriority(currentStock, safetyStock) {
  if (currentStock <= 0) return 5;
  const ratio = currentStock / safetyStock;
  if (ratio < 0.2) return 5;
  if (ratio < 0.4) return 4;
  if (ratio < 0.6) return 3;
  if (ratio < 0.8) return 2;
  return 1;
}
