var hazardAnalysisRouter = router2({
  // 위험 분석 생성
  create: protectedProcedure.input(
    z5.object({
      productId: z5.number(),
      siteId: z5.number(),
      processStep: z5.string(),
      hazardType: z5.enum(["biological", "chemical", "physical"]),
      hazardDescription: z5.string(),
      severity: z5.number().min(1).max(5),
      likelihood: z5.number().min(1).max(5),
      controlMeasures: z5.string().optional(),
      monitoringProcedure: z5.string().optional(),
      criticalLimit: z5.string().optional(),
      analyzedDate: z5.string()
      // YYYY-MM-DD
    })
  ).mutation(async ({ input, ctx: ctx2 }) => {
    const id = await createHazardAnalysis({
      ...input,
      analyzedBy: ctx2.user.id
    });
    return { id };
  }),
  // 제품별 위험 분석 목록 조회
  listByProduct: protectedProcedure.input(z5.object({ productId: z5.number() })).query(async ({ input }) => {
    return getHazardAnalysisByProduct(input.productId);
  }),
  // 위험 분석 상세 조회
  getById: protectedProcedure.input(z5.object({ id: z5.number() })).query(async ({ input }) => {
    return getHazardAnalysisById(input.id);
  }),
  // CCP 지정
  designateAsCcp: protectedProcedure.input(z5.object({ id: z5.number(), ccpNumber: z5.string() })).mutation(async ({ input }) => {
    await updateHazardAnalysis(input.id, {
      isCcp: 1,
      ccpNumber: input.ccpNumber
    });
    return { success: true };
  }),
  // 위험 분석 승인
  approve: protectedProcedure.input(z5.object({ id: z5.number() })).mutation(async ({ input, ctx: ctx2 }) => {
    await updateHazardAnalysis(input.id, {
      status: "approved",
      approvedBy: ctx2.user.id,
      approvedDate: (/* @__PURE__ */ new Date()).toISOString().split("T")[0]
    });
    return { success: true };
  }),
  // 위험 분석 수정
  update: protectedProcedure.input(
    z5.object({
      id: z5.number(),
      processStep: z5.string().optional(),
      hazardType: z5.enum(["biological", "chemical", "physical"]).optional(),
      hazardDescription: z5.string().optional(),
      severity: z5.number().min(1).max(5).optional(),
      likelihood: z5.number().min(1).max(5).optional(),
      isCcp: z5.number().optional(),
      ccpNumber: z5.string().optional(),
      controlMeasures: z5.string().optional(),
      monitoringProcedure: z5.string().optional(),
      criticalLimit: z5.string().optional(),
      status: z5.enum(["draft", "submitted", "approved", "rejected"]).optional(),
      approvedDate: z5.string().optional(),
      reviewDate: z5.string().optional()
    })
  ).mutation(async ({ input, ctx: ctx2 }) => {
    const { id, ...data } = input;
    if (data.status === "approved") {
      await updateHazardAnalysis(id, {
        ...data,
        approvedBy: ctx2.user.id,
        approvedDate: (/* @__PURE__ */ new Date()).toISOString().split("T")[0]
      });
    } else {
      await updateHazardAnalysis(id, data);
    }
    return { success: true };
  }),
  // 위험 분석 삭제
  delete: protectedProcedure.input(z5.object({ id: z5.number() })).mutation(async ({ input }) => {
    await deleteHazardAnalysis(input.id);
    return { success: true };
  }),
  // 사업장별 위험 분석 목록
  listBySite: protectedProcedure.input(z5.object({ siteId: z5.number() })).query(async ({ input }) => {
    return getHazardAnalysisBySite(input.siteId);
  }),
  // 상태별 위험 분석 목록
  listByStatus: protectedProcedure.input(z5.object({ status: z5.enum(["draft", "submitted", "approved", "rejected"]) })).query(async ({ input }) => {
    return getHazardAnalysisByStatus(input.status);
  }),
  // CCP로 지정된 위험 분석 목록
  listCcp: protectedProcedure.input(z5.object({ productId: z5.number() })).query(async ({ input }) => {
    return getCcpHazardAnalysis(input.productId);
  }),
  // 위험 요소 관리 방법 추가
  addControl: protectedProcedure.input(
    z5.object({
      hazardAnalysisId: z5.number(),
      controlType: z5.enum(["preventive", "corrective", "monitoring"]),
      controlDescription: z5.string(),
      responsibility: z5.string().optional(),
      frequency: z5.string().optional(),
      recordForm: z5.string().optional()
    })
  ).mutation(async ({ input }) => {
    const id = await createHazardControl(input);
    return { id };
  }),
  // 위험 분석별 관리 방법 목록
  listControls: protectedProcedure.input(z5.object({ hazardAnalysisId: z5.number() })).query(async ({ input }) => {
    return getHazardControlsByAnalysisId(input.hazardAnalysisId);
  }),
  // 관리 방법 수정
  updateControl: protectedProcedure.input(
    z5.object({
      id: z5.number(),
      controlType: z5.enum(["preventive", "corrective", "monitoring"]).optional(),
      controlDescription: z5.string().optional(),
      responsibility: z5.string().optional(),
      frequency: z5.string().optional(),
      recordForm: z5.string().optional()
    })
  ).mutation(async ({ input }) => {
    const { id, ...data } = input;
    await updateHazardControl(id, data);
    return { success: true };
  }),
  // 관리 방법 삭제
  deleteControl: protectedProcedure.input(z5.object({ id: z5.number() })).mutation(async ({ input }) => {
    await deleteHazardControl(input.id);
    return { success: true };
  })
});

