async function generateRequestNumber(tenantId2) {
  const db2 = await getDb();
  if (!db2) throw new Error("Database not available");
  const today = (/* @__PURE__ */ new Date()).toISOString().split("T")[0].replace(/-/g, "");
  const prefix = `CAR-${today}`;
  const [lastRequest] = await db2.select().from(hCorrectiveActionRequests).where(and12(eq15(hCorrectiveActionRequests.tenantId, tenantId2), eq15(hCorrectiveActionRequests.requestNumber, prefix))).orderBy(desc9(hCorrectiveActionRequests.id)).limit(1);
  if (!lastRequest) {
    return `${prefix}-001`;
  }
  const lastNumber = parseInt(lastRequest.requestNumber.split("-")[2] || "0");
  const nextNumber = (lastNumber + 1).toString().padStart(3, "0");
  return `${prefix}-${nextNumber}`;
}
