async function getPendingTrainingReminders() {
  const db2 = await getDb();
  if (!db2) throw new Error("Database not available");
  const today = /* @__PURE__ */ new Date();
  today.setHours(0, 0, 0, 0);
  return db2.select().from(hTrainingReminders).where(
    and13(
      lte4(hTrainingReminders.reminderDate, today),
      eq16(hTrainingReminders.sent, 0)
    )
  );
}
async function markTrainingReminderAsSent(id) {
  const db2 = await getDb();
  if (!db2) throw new Error("Database not available");
  await db2.update(hTrainingReminders).set({ sent: 1, sentAt: /* @__PURE__ */ new Date() }).where(eq16(hTrainingReminders.id, id));
}
async function issueCertificate(participantId, certificateUrl) {
  const db2 = await getDb();
  if (!db2) throw new Error("Database not available");
  const participant = await getTrainingParticipantById(participantId);
  const certificateNumber = `CERT-${Date.now()}-${participantId}`;
  const course = await getTrainingCourseById(participant.scheduleId);
  let expiryDate;
  if (course && course.validityPeriod) {
    expiryDate = /* @__PURE__ */ new Date();
    expiryDate.setMonth(expiryDate.getMonth() + course.validityPeriod);
  }
  await updateTrainingParticipant(participantId, {
    certificateIssued: 1,
    certificateNumber,
    certificateUrl,
    expiryDate: expiryDate?.toISOString().split("T")[0]
  });
  return { certificateNumber, expiryDate };
}

