// server/pdf/lotTracePdf.ts
import PDFDocument3 from "pdfkit";
import { format } from "date-fns";
import { ko } from "date-fns/locale";
async function generateLotTracePdf(data) {
  return new Promise((resolve, reject) => {
    try {
      const doc = new PDFDocument3({ size: "A4", margin: 50 });
      const buffers = [];
      doc.on("data", buffers.push.bind(buffers));
      doc.on("end", () => {
        const pdfBuffer = Buffer.concat(buffers);
        resolve(pdfBuffer);
      });
      doc.fontSize(20).text("LOT \uCD94\uC801\uC131 \uBCF4\uACE0\uC11C", { align: "center" });
      doc.moveDown();
      doc.fontSize(12);
      doc.text(`\uCD94\uC801 \uC720\uD615: ${data.traceType === "forward" ? "\uC815\uBC29\uD5A5 \uCD94\uC801 (\uC6D0\uC7AC\uB8CC \u2192 \uC644\uC81C\uD488)" : "\uC5ED\uBC29\uD5A5 \uCD94\uC801 (\uC644\uC81C\uD488 \u2192 \uC6D0\uC7AC\uB8CC)"}`);
      doc.text(`\uAC80\uC0C9 LOT \uBC88\uD638: ${data.searchLotNumber}`);
      doc.text(`\uCD94\uC801 \uC77C\uC2DC: ${format(data.tracedAt, "yyyy-MM-dd HH:mm:ss", { locale: ko })}`);
      if (data.tracedBy) {
        doc.text(`\uCD94\uC801\uC790: ${data.tracedBy}`);
      }
      doc.moveDown();
      doc.fontSize(14).text("\uCD94\uC801 \uACB0\uACFC", { underline: true });
      doc.moveDown(0.5);
      const resultData = typeof data.resultData === "string" ? JSON.parse(data.resultData) : data.resultData;
      if (data.traceType === "forward") {
        if (resultData.batches && resultData.batches.length > 0) {
          doc.fontSize(12).text(`\uC0AC\uC6A9\uB41C \uBC30\uCE58: ${resultData.batches.length}\uAC1C`);
          doc.moveDown(0.5);
          resultData.batches.forEach((batch, index16) => {
            doc.fontSize(11).text(`${index16 + 1}. \uBC30\uCE58 \uBC88\uD638: ${batch.batchNumber || "N/A"}`);
            doc.text(`   \uC81C\uD488: ${batch.productName || "N/A"}`);
            doc.text(`   \uC0DD\uC0B0\uC77C: ${batch.productionDate ? format(new Date(batch.productionDate), "yyyy-MM-dd", { locale: ko }) : "N/A"}`);
            doc.text(`   \uC218\uB7C9: ${batch.quantity || "N/A"}`);
            doc.moveDown(0.3);
          });
        } else {
          doc.fontSize(11).text("\uCD94\uC801 \uACB0\uACFC\uAC00 \uC5C6\uC2B5\uB2C8\uB2E4.");
        }
      } else {
        if (resultData.materials && resultData.materials.length > 0) {
          doc.fontSize(12).text(`\uC0AC\uC6A9\uB41C \uC6D0\uC7AC\uB8CC: ${resultData.materials.length}\uAC1C`);
          doc.moveDown(0.5);
          resultData.materials.forEach((material, index16) => {
            doc.fontSize(11).text(`${index16 + 1}. \uC6D0\uC7AC\uB8CC\uBA85: ${material.materialName || "N/A"}`);
            doc.text(`   LOT \uBC88\uD638: ${material.lotNumber || "N/A"}`);
            doc.text(`   \uC785\uACE0\uC77C: ${material.receivedDate ? format(new Date(material.receivedDate), "yyyy-MM-dd", { locale: ko }) : "N/A"}`);
            doc.text(`   \uACF5\uAE09\uC5C5\uCCB4: ${material.supplier || "N/A"}`);
            doc.moveDown(0.3);
          });
        } else {
          doc.fontSize(11).text("\uCD94\uC801 \uACB0\uACFC\uAC00 \uC5C6\uC2B5\uB2C8\uB2E4.");
        }
      }
      doc.moveDown(2);
      doc.fontSize(10).text("\uBCF8 \uBCF4\uACE0\uC11C\uB294 HACCP \uC2DD\uD488 \uC548\uC804 \uAD00\uB9AC \uC2DC\uC2A4\uD15C\uC5D0\uC11C \uC790\uB3D9 \uC0DD\uC131\uB418\uC5C8\uC2B5\uB2C8\uB2E4.", { align: "center" });
      doc.end();
    } catch (error) {
      reject(error);
    }
  });
}

// server/db/traceability.ts
init_db();
init_schema2();
import { eq as eq17, and as and14, inArray as inArray5 } from "drizzle-orm";
async function traceLotForward(lotId, tenantId2) {
  const db2 = await getDb();
  if (!db2) throw new Error("Database not available");
  const [lot] = await db2.select().from(hInventoryLots).where(and14(eq17(hInventoryLots.tenantId, tenantId2), eq17(hInventoryLots.id, lotId)));
  if (!lot) {
    throw new Error("LOT\uC744 \uCC3E\uC744 \uC218 \uC5C6\uC2B5\uB2C8\uB2E4.");
  }
  const batchMaterials = await db2.select({
    batchId: hBatchInputs.batchId,
    quantityUsed: hBatchInputs.actualQuantity,
    uom: hBatchInputs.unit
  }).from(hBatchInputs).where(and14(eq17(hBatchInputs.tenantId, tenantId2), eq17(hBatchInputs.lotId, lotId)));
  if (batchMaterials.length === 0) {
    return {
      lot,
      batches: [],
      message: "\uC774 LOT\uC740 \uC544\uC9C1 \uBC30\uCE58\uC5D0 \uD22C\uC785\uB418\uC9C0 \uC54A\uC558\uC2B5\uB2C8\uB2E4."
    };
  }
  const batchIds = batchMaterials.map((input) => input.batchId);
  const batches = await db2.select({
    batchId: hBatches.id,
    batchCode: hBatches.batchCode,
    productId: hBatches.productId,
    productName: hProducts.productName,
    lotNumber: hBatches.lotNumber,
    status: hBatches.status,
    plannedQuantity: hBatches.plannedQuantity,
    actualQuantity: hBatches.actualQuantity,
    startTime: hBatches.startTime,
    endTime: hBatches.endTime
  }).from(hBatches).leftJoin(hProducts, eq17(hBatches.productId, hProducts.id)).where(inArray5(hBatches.id, batchIds));
  const batchProducts = await db2.select().from(hBatchProducts).where(inArray5(hBatchProducts.batchId, batchIds));
  return {
    lot,
    batches: batches.map((batch) => ({
      ...batch,
      inputQuantity: batchMaterials.find((input) => input.batchId === batch.batchId)?.quantityUsed,
      uom: batchMaterials.find((input) => input.batchId === batch.batchId)?.uom,
      products: batchProducts.filter((p) => p.batchId === batch.batchId)
    }))
  };
}
async function traceLotBackward(batchId, tenantId2) {
  const db2 = await getDb();
  if (!db2) throw new Error("Database not available");
  const [batch] = await db2.select({
    batchId: hBatches.id,
    batchCode: hBatches.batchCode,
    productId: hBatches.productId,
    productName: hProducts.productName,
    lotNumber: hBatches.lotNumber,
    status: hBatches.status,
    plannedQuantity: hBatches.plannedQuantity,
    actualQuantity: hBatches.actualQuantity,
    startTime: hBatches.startTime,
    endTime: hBatches.endTime
  }).from(hBatches).leftJoin(hProducts, eq17(hBatches.productId, hProducts.id)).where(eq17(hBatches.id, batchId));
  if (!batch) {
    throw new Error("\uBC30\uCE58\uB97C \uCC3E\uC744 \uC218 \uC5C6\uC2B5\uB2C8\uB2E4.");
  }
  const materialInputs = await db2.select({
    materialId: hBatchInputs.materialId,
    materialName: hMaterials.materialName,
    lotId: hBatchInputs.lotId,
    lotNumber: hInventoryLots.lotNumber,
    quantityUsed: hBatchInputs.actualQuantity,
    uom: hBatchInputs.unit,
    expiryDate: hInventoryLots.expiryDate
  }).from(hBatchInputs).leftJoin(hMaterials, eq17(hBatchInputs.materialId, hMaterials.id)).leftJoin(hInventoryLots, eq17(hBatchInputs.lotId, hInventoryLots.id)).where(eq17(hBatchInputs.batchId, batchId));
  const batchProducts = await db2.select().from(hBatchProducts).where(and14(eq17(hBatchProducts.tenantId, tenantId2), eq17(hBatchProducts.batchId, batchId)));
  return {
    batch,
    materialInputs,
    products: batchProducts
  };
}
async function traceLotByProductLotNumber(lotNumber, tenantId2) {
  const db2 = await getDb();
  if (!db2) throw new Error("Database not available");
  const [batchProduct] = await db2.select().from(hBatchProducts).where(and14(eq17(hBatchProducts.tenantId, tenantId2), eq17(hBatchProducts.lotNumber, lotNumber)));
  if (!batchProduct) {
    throw new Error("\uD574\uB2F9 LOT \uBC88\uD638\uC758 \uC644\uC81C\uD488\uC744 \uCC3E\uC744 \uC218 \uC5C6\uC2B5\uB2C8\uB2E4.");
  }
  return await traceLotBackward(batchProduct.batchId);
}
async function traceLotByMaterialLotNumber(lotNumber, tenantId2) {
  const db2 = await getDb();
  if (!db2) throw new Error("Database not available");
  const [lot] = await db2.select().from(hInventoryLots).where(and14(eq17(hInventoryLots.tenantId, tenantId2), eq17(hInventoryLots.lotNumber, lotNumber)));
  if (!lot) {
    throw new Error("\uD574\uB2F9 LOT \uBC88\uD638\uC758 \uC6D0\uC7AC\uB8CC\uB97C \uCC3E\uC744 \uC218 \uC5C6\uC2B5\uB2C8\uB2E4.");
  }
  return await traceLotForward(lot.id);
}

