// server/routers/reports.ts
import { z as z9 } from "zod";
var reportsRouter = router2({
  // ============================================================================
  // 위험 분석 보고서
  // ============================================================================
  // 위험 분석 보고서 데이터 조회
  getHazardAnalysisReport: protectedProcedure.input(z9.object({ productId: z9.number() })).query(async ({ input }) => {
    const hazards = await getHazardAnalysisByProduct(input.productId);
    const totalHazards = hazards.length;
    const ccpCount = hazards.filter((h) => h.isCcp === 1).length;
    const highRiskCount = hazards.filter(
      (h) => h.riskLevel === "high" || h.riskLevel === "critical"
    ).length;
    return {
      hazards,
      statistics: {
        totalHazards,
        ccpCount,
        highRiskCount,
        approvedCount: hazards.filter((h) => h.status === "approved").length
      }
    };
  }),
  // ============================================================================
  // 시정 조치 이력 보고서
  // ============================================================================
  // 시정 조치 이력 보고서 데이터 조회
  getCorrectiveActionReport: protectedProcedure.input(
    z9.object({
      startDate: z9.string(),
      endDate: z9.string(),
      batchId: z9.number().optional()
    })
  ).query(async ({ input }) => {
    const actions = input.batchId ? await getCorrectiveActionRequestsByBatch(input.batchId) : await getCorrectiveActionRequestsByStatus("closed");
    const filteredActions = actions.filter((action) => {
      const occurredAt = new Date(action.occurredAt);
      const start = new Date(input.startDate);
      const end = new Date(input.endDate);
      return occurredAt >= start && occurredAt <= end;
    });
    const totalActions = filteredActions.length;
    const effectiveActions = filteredActions.filter((a) => a.isEffective === 1).length;
    const avgResolutionTime = filteredActions.reduce((sum2, action) => {
      if (action.actionCompletedDate && action.occurredAt) {
        const completed = new Date(action.actionCompletedDate);
        const occurred = new Date(action.occurredAt);
        return sum2 + (completed.getTime() - occurred.getTime()) / (1e3 * 60 * 60 * 24);
      }
      return sum2;
    }, 0) / totalActions;
    return {
      actions: filteredActions,
      statistics: {
        totalActions,
        effectiveActions,
        effectivenessRate: totalActions > 0 ? effectiveActions / totalActions * 100 : 0,
        avgResolutionTime: Math.round(avgResolutionTime * 10) / 10
      }
    };
  }),
  // ============================================================================
  // 교육 이수 증명서
  // ============================================================================
  // 교육 이수 증명서 데이터 조회
  getTrainingCertificate: protectedProcedure.input(z9.object({ participantId: z9.number() })).query(async ({ input }) => {
    const participant = await getTrainingParticipantById(input.participantId);
    if (!participant) {
      throw new Error("\uCC38\uAC00\uC790 \uC815\uBCF4\uB97C \uCC3E\uC744 \uC218 \uC5C6\uC2B5\uB2C8\uB2E4.");
    }
    const schedule2 = await getTrainingScheduleById(participant.scheduleId);
    if (!schedule2) {
      throw new Error("\uAD50\uC721 \uC77C\uC815 \uC815\uBCF4\uB97C \uCC3E\uC744 \uC218 \uC5C6\uC2B5\uB2C8\uB2E4.");
    }
    const course = await getTrainingCourseById(schedule2.courseId);
    if (!course) {
      throw new Error("\uAD50\uC721 \uACFC\uC815 \uC815\uBCF4\uB97C \uCC3E\uC744 \uC218 \uC5C6\uC2B5\uB2C8\uB2E4.");
    }
    return {
      participant,
      schedule: schedule2,
      course,
      certificateInfo: {
        certificateNumber: participant.certificateNumber,
        issuedDate: (/* @__PURE__ */ new Date()).toISOString().split("T")[0],
        expiryDate: participant.expiryDate
      }
    };
  }),
  // 사용자별 교육 이수 현황 보고서
  getUserTrainingReport: protectedProcedure.input(z9.object({ userId: z9.number() })).query(async ({ input }) => {
    const participants = await getTrainingParticipantsByUser(input.userId);
    const totalTrainings = participants.length;
    const completedTrainings = participants.filter((p) => p.passed === 1).length;
    const upcomingTrainings = participants.filter((p) => p.attendanceStatus === "registered").length;
    const expiringTrainings = participants.filter((p) => {
      if (!p.expiryDate) return false;
      const expiryDate = new Date(p.expiryDate);
      const today = /* @__PURE__ */ new Date();
      const daysUntilExpiry = (expiryDate.getTime() - today.getTime()) / (1e3 * 60 * 60 * 24);
      return daysUntilExpiry > 0 && daysUntilExpiry <= 30;
    });
    return {
      participants,
      statistics: {
        totalTrainings,
        completedTrainings,
        upcomingTrainings,
        expiringCount: expiringTrainings.length,
        completionRate: totalTrainings > 0 ? completedTrainings / totalTrainings * 100 : 0
      }
    };
  })
});

