        ccpType: ccpMonitoringRecords.ccpType,
        totalRecords: sql15`COUNT(*)`,
        passedRecords: sql15`SUM(CASE WHEN ${ccpMonitoringRecords.passFail} = '\uC801\uD569' THEN 1 ELSE 0 END)`,
