import { z as z24 } from "zod";

// server/db/accountCategories.ts
init_db();
async function getAllAccountCategories() {
  const db2 = await getRawConnection();
  const [result] = await db2.execute(
    `SELECT 
      id, 
      code, 
      name, 
      major_category as majorCategory, 
      minor_category as minorCategory, 
      description, 
      is_active as isActive, 
      created_at as createdAt, 
      updated_at as updatedAt
    FROM account_categories 
    WHERE is_active = 1 
    ORDER BY code ASC`
  );
  return result;
}
async function getAccountCategoriesByMajor(majorCategory) {
  const db2 = await getRawConnection();
  const [result] = await db2.execute(
    `SELECT 
      id, 
      code, 
      name, 
      major_category as majorCategory, 
      minor_category as minorCategory, 
      description, 
      is_active as isActive, 
      created_at as createdAt, 
      updated_at as updatedAt
    FROM account_categories 
    WHERE is_active = 1 AND major_category = ? 
    ORDER BY code ASC`,
    [majorCategory]
  );
  return result;
}
async function createAccountCategory(data) {
  const db2 = await getRawConnection();
  const [existing] = await db2.execute(
    `SELECT id FROM account_categories WHERE code = ? LIMIT 1`,
    [data.code]
  );
  if (existing && existing.length > 0) {
    throw new Error("\uC774\uBBF8 \uC874\uC7AC\uD558\uB294 \uACC4\uC815 \uCF54\uB4DC\uC785\uB2C8\uB2E4");
  }
  const [result] = await db2.execute(
    `INSERT INTO account_categories (code, name, major_category, minor_category, description) 
     VALUES (?, ?, ?, ?, ?)`,
    [
      data.code,
      data.name,
      data.majorCategory,
      data.minorCategory || null,
      data.description || null
    ]
  );
  return { id: result.insertId };
}
async function updateAccountCategory(id, data) {
  const db2 = await getRawConnection();
  if (data.code) {
    const [existing] = await db2.execute(
      `SELECT id FROM account_categories WHERE code = ? AND id != ? LIMIT 1`,
      [data.code, id]
    );
    if (existing && existing.length > 0) {
      throw new Error("\uC774\uBBF8 \uC874\uC7AC\uD558\uB294 \uACC4\uC815 \uCF54\uB4DC\uC785\uB2C8\uB2E4");
    }
  }
  const updates = [];
  const values = [];
  if (data.code !== void 0) {
    updates.push("code = ?");
    values.push(data.code);
  }
  if (data.name !== void 0) {
    updates.push("name = ?");
    values.push(data.name);
  }
  if (data.majorCategory !== void 0) {
    updates.push("major_category = ?");
    values.push(data.majorCategory);
  }
  if (data.minorCategory !== void 0) {
    updates.push("minor_category = ?");
    values.push(data.minorCategory || null);
  }
  if (data.description !== void 0) {
    updates.push("description = ?");
    values.push(data.description || null);
  }
  if (updates.length === 0) {
    throw new Error("\uC218\uC815\uD560 \uB0B4\uC6A9\uC774 \uC5C6\uC2B5\uB2C8\uB2E4");
  }
  values.push(id);
  await db2.execute(
    `UPDATE account_categories SET ${updates.join(", ")} WHERE id = ?`,
    values
  );
  return { success: true };
}
async function deleteAccountCategory(id) {
  const db2 = await getRawConnection();
  await db2.execute(
    `UPDATE account_categories SET is_active = 0 WHERE id = ?`,
    [id]
  );
  return { success: true };
}
async function getAccountCategoryById(id) {
  const db2 = await getRawConnection();
  const [result] = await db2.execute(
    `SELECT 
      id, 
      code, 
      name, 
      major_category as majorCategory, 
      minor_category as minorCategory, 
      description, 
      is_active as isActive, 
      created_at as createdAt, 
      updated_at as updatedAt
    FROM account_categories 
    WHERE id = ? LIMIT 1`,
    [id]
  );
  const rows = result;
  if (!rows || rows.length === 0) {
    throw new Error("\uACC4\uC815 \uACFC\uBAA9\uC744 \uCC3E\uC744 \uC218 \uC5C6\uC2B5\uB2C8\uB2E4");
  }
  return rows[0];
}

// server/routers/accountCategoriesRouter.ts
var accountCategoriesRouter = router2({
  /**
   * 전체 계정 과목(카테고리) 목록 조회
   */
  getAll: protectedProcedure.query(async () => {
    return await getAllAccountCategories();
  }),
  /**
   * 대분류별 계정 과목 조회
   */
  getByMajor: protectedProcedure.input(z24.object({ majorCategory: z24.string() })).query(async ({ input }) => {
    return await getAccountCategoriesByMajor(input.majorCategory);
  }),
  /**
   * 계정 과목 상세 조회
   */
  getById: protectedProcedure.input(z24.object({ id: z24.number() })).query(async ({ input }) => {
    return await getAccountCategoryById(input.id);
  }),
  /**
   * 계정 과목 등록
   */
  create: protectedProcedure.input(
    z24.object({
      code: z24.string().min(1).max(20),
      name: z24.string().min(1).max(100),
      majorCategory: z24.string().min(1).max(50),
      minorCategory: z24.string().max(50).optional(),
      description: z24.string().optional()
    })
  ).mutation(async ({ input }) => {
    return await createAccountCategory(input);
  }),
  /**
   * 계정 과목 수정
   */
  update: protectedProcedure.input(
    z24.object({
      id: z24.number(),
      code: z24.string().min(1).max(20).optional(),
      name: z24.string().min(1).max(100).optional(),
      majorCategory: z24.string().min(1).max(50).optional(),
      minorCategory: z24.string().max(50).optional(),
      description: z24.string().optional()
    })
  ).mutation(async ({ input }) => {
    const { id, ...data } = input;
    return await updateAccountCategory(id, data);
  }),
  /**
   * 계정 과목 삭제 (소프트 삭제)
   */
  delete: protectedProcedure.input(z24.object({ id: z24.number() })).mutation(async ({ input }) => {
    return await deleteAccountCategory(input.id);
  }),
  /**
   * 대분류 목록 조회 (고유한 major_category 값들)
   */
  getMajorCategories: protectedProcedure.query(async () => {
    const all = await getAllAccountCategories();
    const majors = [...new Set(all.map((c) => c.majorCategory))];
    return majors;
  }),
  /**
   * 목록 조회 (accountingAccountCategories.list 호환)
   */
  list: protectedProcedure.query(async () => {
    return await getAllAccountCategories();
  })
});

