      transactionType: "adjustment",
      // 취소는 조정으로 처리
      quantity: (-Number(purchase.quantity || 0)).toString(),
      unit: purchase.unit || "EA",
      transactionDate: (/* @__PURE__ */ new Date()).toISOString().split("T")[0],
      // 취소 일자
      sourceType,
