      // 액션 필터
      entityType: z27.string().optional(),
      // 엔티티 타입 필터
      userId: z27.number().optional(),
      // 사용자 ID 필터
      userEmail: z27.string().optional(),
      // 사용자 이메일 검색
      startDate: z27.string().optional(),
      // 시작 날짜 (YYYY-MM-DD)
      endDate: z27.string().optional(),
      // 종료 날짜 (YYYY-MM-DD)
      search: z27.string().optional()
