var tenantsPublicRouter = router2({
  // 전체 테넌트 목록 조회 (공개 API)
  getAll: publicProcedure.query(async () => {
    const db2 = await getDb();
    if (!db2) throw new TRPCError19({ code: "INTERNAL_SERVER_ERROR", message: "Database not initialized" });
    const allTenants = await db2.select({
      id: tenants.id,
      name: tenants.name,
      createdAt: tenants.createdAt,
      isActive: sql24`${tenants.status} = 'active'`,
      _count: {
        users: count4(users.id)
      }
    }).from(tenants).leftJoin(users, eq47(users.tenantId, tenants.id)).groupBy(tenants.id, tenants.name, tenants.createdAt, tenants.status).orderBy(asc6(tenants.name));
    return {
      success: true,
      tenants: allTenants
    };
  })
});

