async function getNonconformingProductDashboard(siteId, tenantId2) {
  const db2 = await getDb();
  if (!db2) throw new Error("\uB370\uC774\uD130\uBCA0\uC774\uC2A4 \uC5F0\uACB0 \uC2E4\uD328");
  const [totalStats] = await db2.select({
    total: sql31`COUNT(*)`,
    detected: sql31`SUM(CASE WHEN status = 'detected' THEN 1 ELSE 0 END)`,
    underInvestigation: sql31`SUM(CASE WHEN status = 'under_investigation' THEN 1 ELSE 0 END)`,
    pendingDisposal: sql31`SUM(CASE WHEN status = 'pending_disposal' THEN 1 ELSE 0 END)`,
    disposed: sql31`SUM(CASE WHEN status = 'disposed' THEN 1 ELSE 0 END)`,
    closed: sql31`SUM(CASE WHEN status = 'closed' THEN 1 ELSE 0 END)`
  }).from(h_nonconforming_products).where(and42(eq53(h_nonconforming_products.tenantId, tenantId2), eq53(h_nonconforming_products.siteId, siteId)));
  const detectionSourceStats = await db2.select({
    detectionSource: h_nonconforming_products.detectionSource,
    count: sql31`COUNT(*)`
  }).from(h_nonconforming_products).where(and42(eq53(h_nonconforming_products.tenantId, tenantId2), eq53(h_nonconforming_products.siteId, siteId))).groupBy(h_nonconforming_products.detectionSource);
  const nonconformityTypeStats = await db2.select({
    nonconformityType: h_nonconforming_products.nonconformityType,
    count: sql31`COUNT(*)`
  }).from(h_nonconforming_products).where(and42(eq53(h_nonconforming_products.tenantId, tenantId2), eq53(h_nonconforming_products.siteId, siteId))).groupBy(h_nonconforming_products.nonconformityType);
  const disposalMethodStats = await db2.select({
    disposalMethod: h_nonconforming_products.disposalMethod,
    count: sql31`COUNT(*)`
  }).from(h_nonconforming_products).where(and42(eq53(h_nonconforming_products.tenantId, tenantId2), eq53(h_nonconforming_products.siteId, siteId))).groupBy(h_nonconforming_products.disposalMethod);
  const monthlyTrend = await db2.select({
    month: sql31`DATE_FORMAT(detection_date, '%Y-%m')`,
    count: sql31`COUNT(*)`
  }).from(h_nonconforming_products).where(
    and42(
      eq53(h_nonconforming_products.tenantId, tenantId2),
      eq53(h_nonconforming_products.siteId, siteId),
      gte21(h_nonconforming_products.detectionDate, sql31`DATE_SUB(CURDATE(), INTERVAL 12 MONTH)`)
    )
  ).groupBy(sql31`DATE_FORMAT(detection_date, '%Y-%m')`).orderBy(sql31`DATE_FORMAT(detection_date, '%Y-%m')`);
  return {
    totalStats,
    detectionSourceStats,
    nonconformityTypeStats,
    disposalMethodStats,
    monthlyTrend
  };
}
async function calculateNonconformityRate(filters, tenantId2) {
  const db2 = await getDb();
  if (!db2) throw new Error("\uB370\uC774\uD130\uBCA0\uC774\uC2A4 \uC5F0\uACB0 \uC2E4\uD328");
  const [ncpResult] = await db2.select({
    totalQuantity: sql31`SUM(quantity)`,
    totalCount: sql31`COUNT(*)`
  }).from(h_nonconforming_products).where(
    and42(
      eq53(h_nonconforming_products.tenantId, tenantId2),
      eq53(h_nonconforming_products.siteId, filters.siteId),
      gte21(h_nonconforming_products.detectionDate, filters.dateFrom),
      lte20(h_nonconforming_products.detectionDate, filters.dateTo)
    )
  );
  return {
    ncpQuantity: ncpResult?.totalQuantity || 0,
    ncpCount: ncpResult?.totalCount || 0
  };
}
async function generateNonconformingProductReport(filters, tenantId2) {
  const db2 = await getDb();
  if (!db2) throw new Error("\uB370\uC774\uD130\uBCA0\uC774\uC2A4 \uC5F0\uACB0 \uC2E4\uD328");
  const products = await getNonconformingProducts({
    siteId: filters.siteId,
    dateFrom: filters.dateFrom,
    dateTo: filters.dateTo
  });
  const dashboard = await getNonconformingProductDashboard(filters.siteId);
  const rate = await calculateNonconformityRate(filters);
  return {
    period: {
      from: filters.dateFrom,
      to: filters.dateTo
    },
    summary: {
      totalCount: products.length,
      ...dashboard.totalStats
    },
    statistics: {
      byDetectionSource: dashboard.detectionSourceStats,
      byNonconformityType: dashboard.nonconformityTypeStats,
      byDisposalMethod: dashboard.disposalMethodStats
    },
    trend: dashboard.monthlyTrend,
    nonconformityRate: rate,
    products
  };
}

