async function getRecallDashboard(tenantId2, siteId) {
  const db2 = await getDb();
  if (!db2) throw new Error("\uB370\uC774\uD130\uBCA0\uC774\uC2A4 \uC5F0\uACB0 \uC2E4\uD328");
  if (!tenantId2) throw new Error("tenantId is required");
  const [totalStats] = await db2.select({
    total: sql32`COUNT(*)`,
    planned: sql32`SUM(CASE WHEN status = 'planned' THEN 1 ELSE 0 END)`,
    inProgress: sql32`SUM(CASE WHEN status = 'in_progress' THEN 1 ELSE 0 END)`,
    completed: sql32`SUM(CASE WHEN status = 'completed' THEN 1 ELSE 0 END)`,
    avgOverallScore: sql32`AVG(overall_score)`,
    avgRecallRate: sql32`AVG(actual_recall_rate)`
  }).from(h_recall_simulations).where(
    and43(
      eq54(h_recall_simulations.siteId, siteId),
      eq54(h_recall_simulations.tenantId, tenantId2)
    )
  );
  const resultDistribution = await db2.select({
    result: h_recall_simulations.result,
    count: sql32`COUNT(*)`
  }).from(h_recall_simulations).where(
    and43(
      eq54(h_recall_simulations.siteId, siteId),
      eq54(h_recall_simulations.tenantId, tenantId2),
      eq54(h_recall_simulations.status, "completed")
    )
  ).groupBy(h_recall_simulations.result);
  const yearlyTrend = await db2.select({
    year: sql32`YEAR(simulation_date)`,
    count: sql32`COUNT(*)`,
    avgScore: sql32`AVG(overall_score)`
  }).from(h_recall_simulations).where(
    and43(
      eq54(h_recall_simulations.siteId, siteId),
      eq54(h_recall_simulations.tenantId, tenantId2)
    )
  ).groupBy(sql32`YEAR(simulation_date)`).orderBy(sql32`YEAR(simulation_date)`);
  return { totalStats, resultDistribution, yearlyTrend };
}

