  // ============================================
  // 월간 마감 v2 (Accounting Monthly Summary)
  // ============================================
  accountingMonthly: router2({
    // 월 마감 집계 생성
    generateSummary: adminProcedure.input(
      z44.object({
        year: z44.number().int().min(2020).max(2100),
        month: z44.number().int().min(1).max(12),
        highAmountThreshold: z44.number().optional().default(1e6)
      })
    ).mutation(async ({ input, ctx: ctx2 }) => {
      const summaryDb = await Promise.resolve().then(() => (init_accountingMonthlySummary(), accountingMonthlySummary_exports));
      const calculated = await summaryDb.calculateMonthlySummary(input.year, input.month, ctx2.user.tenantId);
      const summaryId = await summaryDb.upsertMonthlySummary({
        year: input.year,
        month: input.month,
        totalDeposit: calculated.totalDeposit,
        totalWithdrawal: calculated.totalWithdrawal,
        netCashFlow: calculated.netCashFlow,
        totalDays: calculated.totalDays,
        closedDays: calculated.closedDays,
        missingDays: calculated.missingDays,
        highAmountThreshold: input.highAmountThreshold.toFixed(2),
        status: "draft"
      }, ctx2.user.tenantId);
      const highAmountCount = await summaryDb.extractHighAmountTransactions(
        summaryId,
        input.year,
        input.month,
        input.highAmountThreshold,
        ctx2.user.tenantId
      );
      await summaryDb.upsertMonthlySummary({
        year: input.year,
        month: input.month,
        totalDeposit: calculated.totalDeposit,
        totalWithdrawal: calculated.totalWithdrawal,
        netCashFlow: calculated.netCashFlow,
        totalDays: calculated.totalDays,
        closedDays: calculated.closedDays,
        missingDays: calculated.missingDays,
        highAmountCount,
        highAmountThreshold: input.highAmountThreshold.toFixed(2),
        status: "draft"
      }, ctx2.user.tenantId);
      return {
        success: true,
        summaryId,
        totalDeposit: calculated.totalDeposit,
        totalWithdrawal: calculated.totalWithdrawal,
        netCashFlow: calculated.netCashFlow,
        closedDays: calculated.closedDays,
        totalDays: calculated.totalDays,
        missingDays: JSON.parse(calculated.missingDays),
        highAmountCount
      };
    }),
    // 월 마감 확정
    confirmClose: adminProcedure.input(
      z44.object({
        year: z44.number().int().min(2020).max(2100),
        month: z44.number().int().min(1).max(12)
      })
    ).mutation(async ({ input, ctx: ctx2 }) => {
      const summaryDb = await Promise.resolve().then(() => (init_accountingMonthlySummary(), accountingMonthlySummary_exports));
      const summary = await summaryDb.getMonthlySummary(input.year, input.month);
      if (!summary) {
        throw new TRPCError22({
          code: "NOT_FOUND",
          message: "\uC6D4 \uB9C8\uAC10 \uB370\uC774\uD130\uAC00 \uC874\uC7AC\uD558\uC9C0 \uC54A\uC2B5\uB2C8\uB2E4. \uBA3C\uC800 \uC9D1\uACC4\uB97C \uC0DD\uC131\uD574\uC8FC\uC138\uC694."
        });
      }
      if (summary.status === "locked") {
        throw new TRPCError22({
          code: "BAD_REQUEST",
          message: "\uC774\uBBF8 \uC7A0\uAE08\uB41C \uC6D4 \uB9C8\uAC10\uC785\uB2C8\uB2E4."
        });
      }
      await summaryDb.updateMonthlySummaryStatus(summary.id, "confirmed", ctx2.user.id, ctx2.user.tenantId);
      return {
        success: true,
        message: "\uC6D4 \uB9C8\uAC10\uC774 \uD655\uC815\uB418\uC5C8\uC2B5\uB2C8\uB2E4."
      };
    }),
    // 월 마감 잠금
    lockClose: adminProcedure.input(
      z44.object({
        year: z44.number().int().min(2020).max(2100),
        month: z44.number().int().min(1).max(12)
      })
    ).mutation(async ({ input, ctx: ctx2 }) => {
      const summaryDb = await Promise.resolve().then(() => (init_accountingMonthlySummary(), accountingMonthlySummary_exports));
      const summary = await summaryDb.getMonthlySummary(input.year, input.month);
      if (!summary) {
        throw new TRPCError22({
          code: "NOT_FOUND",
          message: "\uC6D4 \uB9C8\uAC10 \uB370\uC774\uD130\uAC00 \uC874\uC7AC\uD558\uC9C0 \uC54A\uC2B5\uB2C8\uB2E4."
        });
      }
      if (summary.status !== "confirmed") {
        throw new TRPCError22({
          code: "BAD_REQUEST",
          message: "\uD655\uC815\uB41C \uC6D4 \uB9C8\uAC10\uB9CC \uC7A0\uAE08\uD560 \uC218 \uC788\uC2B5\uB2C8\uB2E4."
        });
      }
      await summaryDb.updateMonthlySummaryStatus(summary.id, "locked", ctx2.user.id);
      return {
        success: true,
        message: "\uC6D4 \uB9C8\uAC10\uC774 \uC7A0\uAE08\uB418\uC5C8\uC2B5\uB2C8\uB2E4. \uB354 \uC774\uC0C1 \uC218\uC815\uD560 \uC218 \uC5C6\uC2B5\uB2C8\uB2E4."
      };
    }),
    // 월 마감 목록 조회
    list: protectedProcedure.input(
      z44.object({
        limit: z44.number().optional().default(12)
      })
    ).query(async ({ input, ctx: ctx2 }) => {
      const summaryDb = await Promise.resolve().then(() => (init_accountingMonthlySummary(), accountingMonthlySummary_exports));
      return await summaryDb.listMonthlySummaries(input.limit, ctx2.user.tenantId);
    }),
    // 월 마감 상세 조회
    getDetail: protectedProcedure.input(
      z44.object({
        year: z44.number().int().min(2020).max(2100),
        month: z44.number().int().min(1).max(12)
      })
    ).query(async ({ input, ctx: ctx2 }) => {
      const summaryDb = await Promise.resolve().then(() => (init_accountingMonthlySummary(), accountingMonthlySummary_exports));
      const summary = await summaryDb.getMonthlySummary(input.year, input.month);
      if (!summary) {
        return null;
      }
      const highAmountTransactions = await summaryDb.getHighAmountTransactions(summary.id, ctx2.user.tenantId);
      const reports = await summaryDb.getMonthlyReports(summary.id, ctx2.user.tenantId);
      return {
        ...summary,
        missingDays: summary.missingDays ? JSON.parse(summary.missingDays) : [],
        highAmountTransactions,
        reports
      };
    }),
    // PDF 리포트 생성 (placeholder)
    generatePDF: adminProcedure.input(
      z44.object({
        year: z44.number().int().min(2020).max(2100),
        month: z44.number().int().min(1).max(12)
      })
    ).mutation(async ({ input, ctx: ctx2 }) => {
      const summaryDb = await Promise.resolve().then(() => (init_accountingMonthlySummary(), accountingMonthlySummary_exports));
      const { generatePDF: generatePDF2, generateMonthlyReportHTML: generateMonthlyReportHTML2 } = await Promise.resolve().then(() => (init_pdfGenerator(), pdfGenerator_exports));
      const summary = await summaryDb.getMonthlySummary(input.year, input.month);
      if (!summary) {
        throw new TRPCError22({
          code: "NOT_FOUND",
          message: "\uC6D4 \uB9C8\uAC10 \uB370\uC774\uD130\uAC00 \uC874\uC7AC\uD558\uC9C0 \uC54A\uC2B5\uB2C8\uB2E4."
        });
      }
      const highAmountTransactions = await summaryDb.getHighAmountTransactions(summary.id);
      const html = generateMonthlyReportHTML2({
        year: input.year,
        month: input.month,
        totalIncome: parseFloat(summary.totalDeposit),
        totalExpense: parseFloat(summary.totalWithdrawal),
        netCashFlow: parseFloat(summary.netCashFlow),
        highAmountTransactions: highAmountTransactions.map((tx) => ({
          date: new Date(tx.transactionDate).toLocaleDateString("ko-KR"),
          description: tx.description || "",
          amount: parseFloat(tx.amount),
          type: tx.transactionType
        })),
        missingDates: summary.missingDays ? JSON.parse(summary.missingDays) : []
      });
      const fileName = `${input.year}\uB144_${input.month}\uC6D4_\uC6D4\uB9C8\uAC10\uB9AC\uD3EC\uD2B8`;
      const { url: fileUrl, key: fileKey } = await generatePDF2({
        html,
        filename: fileName,
        format: "A4",
        landscape: false,
        tenantId: ctx2.user.tenantId
      });
      const reportId = await summaryDb.saveMonthlyReport({
        summaryId: summary.id,
        fileKey,
        fileUrl,
        fileName: `${fileName}.pdf`,
        fileSize: null,
        // puppeteer는 파일 크기를 반환하지 않음
        generatedBy: ctx2.user.id
      }, ctx2.user.tenantId);
      return {
        success: true,
        reportId,
        fileUrl,
        fileName: `${fileName}.pdf`
      };
    })
  }),
