// server/_core/approvalAutomationScheduler.ts
import cron3 from "node-cron";

// server/schedulers/approvalAutomation.ts
init_db();
init_schema2();
import { eq as eq108, and as and93 } from "drizzle-orm";
async function processAutoApprovals() {
  const db2 = await getDb();
  if (!db2) {
    console.error("[\uC2B9\uC778 \uC790\uB3D9\uD654] Database connection failed");
    return { success: false, processedCount: 0 };
  }
  try {
    console.log("[\uC2B9\uC778 \uC790\uB3D9\uD654] \uC790\uB3D9 \uC2B9\uC778 \uC870\uAC74 \uCCB4\uD06C \uC2DC\uC791");
    const activeTenants = await db2.select({ id: tenants.id }).from(tenants).where(eq108(tenants.status, "active"));
    let totalProcessedCount = 0;
    for (const tenant of activeTenants) {
      const tenantId2 = tenant.id;
      const pendingRequests = await db2.select().from(hApprovalRequests).where(
        and93(
          eq108(hApprovalRequests.tenantId, tenantId2),
          eq108(hApprovalRequests.status, "pending")
        )
      );
      if (pendingRequests.length === 0) {
        continue;
      }
      let processedCount = 0;
      for (const request of pendingRequests) {
        let autoApprove = false;
        let reason = "";
        if (request.requestType === "batch_approval" && request.referenceId) {
          const batch = await db2.select().from(hBatches).where(
            and93(
              eq108(hBatches.id, request.referenceId),
              eq108(hBatches.tenantId, tenantId2)
            )
          ).limit(1);
          if (batch.length > 0) {
            const batchData = batch[0];
            const plannedQty = parseFloat(batchData.plannedQuantity);
            if (plannedQty && plannedQty <= 100) {
              autoApprove = true;
              reason = "\uC18C\uB7C9 \uBC30\uCE58 \uC790\uB3D9 \uC2B9\uC778 (100\uAC1C \uC774\uD558)";
            }
          }
        }
        if (request.requestType === "inventory_adjustment" && request.referenceId) {
          const adjustment = await db2.select().from(hInventoryAdjustments).where(
            and93(
              eq108(hInventoryAdjustments.id, request.referenceId),
              eq108(hInventoryAdjustments.tenantId, tenantId2)
            )
          ).limit(1);
          if (adjustment.length > 0) {
            const adjustmentData = adjustment[0];
            const quantityDiff = Math.abs(parseFloat(adjustmentData.quantityAfter) - parseFloat(adjustmentData.quantityBefore));
            if (quantityDiff <= 10) {
              autoApprove = true;
              reason = "\uC18C\uB7C9 \uC7AC\uACE0 \uC870\uC815 \uC790\uB3D9 \uC2B9\uC778 (10\uAC1C \uC774\uD558)";
            }
          }
        }
        if (autoApprove) {
          await db2.update(hApprovalRequests).set({
            status: "approved",
            approvedAt: /* @__PURE__ */ new Date(),
            notes: reason
          }).where(
            and93(
              eq108(hApprovalRequests.id, request.id),
              eq108(hApprovalRequests.tenantId, tenantId2)
            )
          );
          console.log(`[\uC2B9\uC778 \uC790\uB3D9\uD654] [tenant:${tenantId2}] \uC790\uB3D9 \uC2B9\uC778 \uCC98\uB9AC: ${request.title} (${reason})`);
          processedCount++;
        }
      }
      if (processedCount > 0) {
        console.log(`[\uC2B9\uC778 \uC790\uB3D9\uD654] [tenant:${tenantId2}] ${processedCount}\uAC1C \uC2B9\uC778 \uC694\uCCAD \uC790\uB3D9 \uCC98\uB9AC \uC644\uB8CC`);
      }
      totalProcessedCount += processedCount;
    }
    console.log(`[\uC2B9\uC778 \uC790\uB3D9\uD654] \uC804\uCCB4 ${totalProcessedCount}\uAC1C \uC2B9\uC778 \uC694\uCCAD \uC790\uB3D9 \uCC98\uB9AC \uC644\uB8CC`);
    return { success: true, processedCount: totalProcessedCount };
  } catch (error) {
    console.error("[\uC2B9\uC778 \uC790\uB3D9\uD654] Error:", error);
    return { success: false, processedCount: 0 };
  }
}
async function assignReviewers() {
  const db2 = await getDb();
  if (!db2) {
    console.error("[\uC2B9\uC778 \uC790\uB3D9\uD654] Database connection failed");
    return { success: false, assignedCount: 0 };
  }
  try {
    console.log("[\uC2B9\uC778 \uC790\uB3D9\uD654] \uAC80\uD1A0\uC790 \uC790\uB3D9 \uBC30\uC815 \uC2DC\uC791");
    const activeTenants = await db2.select({ id: tenants.id }).from(tenants).where(eq108(tenants.status, "active"));
    let totalAssignedCount = 0;
    for (const tenant of activeTenants) {
      const tenantId2 = tenant.id;
      const unassignedRequests = await db2.select().from(hApprovalRequests).where(
        and93(
          eq108(hApprovalRequests.tenantId, tenantId2),
          eq108(hApprovalRequests.status, "pending")
        )
      );
      if (unassignedRequests.length === 0) {
        continue;
      }
      const reviewers = await db2.select().from(users).where(
        and93(
          eq108(users.tenantId, tenantId2),
          eq108(users.role, "admin")
        )
      );
      if (reviewers.length === 0) {
        console.warn(`[\uC2B9\uC778 \uC790\uB3D9\uD654] [tenant:${tenantId2}] \uAC80\uD1A0\uC790\uB97C \uCC3E\uC744 \uC218 \uC5C6\uC74C`);
        continue;
      }
      let assignedCount = 0;
      for (let i = 0; i < unassignedRequests.length; i++) {
        const request = unassignedRequests[i];
        const reviewer = reviewers[i % reviewers.length];
        console.log(`[\uC2B9\uC778 \uC790\uB3D9\uD654] [tenant:${tenantId2}] \uAC80\uD1A0\uC790 \uBC30\uC815: ${request.title} \u2192 ${reviewer.name}`);
        assignedCount++;
      }
      if (assignedCount > 0) {
        console.log(`[\uC2B9\uC778 \uC790\uB3D9\uD654] [tenant:${tenantId2}] ${assignedCount}\uAC1C \uC2B9\uC778 \uC694\uCCAD\uC5D0 \uAC80\uD1A0\uC790 \uBC30\uC815 \uC644\uB8CC`);
      }
      totalAssignedCount += assignedCount;
    }
    console.log(`[\uC2B9\uC778 \uC790\uB3D9\uD654] \uC804\uCCB4 ${totalAssignedCount}\uAC1C \uC2B9\uC778 \uC694\uCCAD\uC5D0 \uAC80\uD1A0\uC790 \uBC30\uC815 \uC644\uB8CC`);
    return { success: true, assignedCount: totalAssignedCount };
  } catch (error) {
    console.error("[\uC2B9\uC778 \uC790\uB3D9\uD654] Error:", error);
    return { success: false, assignedCount: 0 };
  }
}

// server/_core/approvalAutomationScheduler.ts
function initApprovalAutomationScheduler() {
  cron3.schedule("0 10 * * *", async () => {
    console.log("[Scheduler] \uC2B9\uC778 \uC790\uB3D9\uD654 \uC2A4\uCF00\uC904\uB7EC \uC2E4\uD589 - \uC790\uB3D9 \uC2B9\uC778 \uCC98\uB9AC");
    try {
      const result = await processAutoApprovals();
      if (result.success) {
        console.log(`[Scheduler] \uC790\uB3D9 \uC2B9\uC778 ${result.processedCount}\uAC1C \uCC98\uB9AC \uC644\uB8CC`);
      } else {
        console.error("[Scheduler] \uC790\uB3D9 \uC2B9\uC778 \uCC98\uB9AC \uC2E4\uD328");
      }
    } catch (error) {
      console.error("[Scheduler] \uC790\uB3D9 \uC2B9\uC778 \uC2A4\uCF00\uC904\uB7EC \uC624\uB958:", error);
    }
  });
  cron3.schedule("0 9 * * *", async () => {
    console.log("[Scheduler] \uC2B9\uC778 \uC790\uB3D9\uD654 \uC2A4\uCF00\uC904\uB7EC \uC2E4\uD589 - \uAC80\uD1A0\uC790 \uC790\uB3D9 \uBC30\uC815");
    try {
      const result = await assignReviewers();
      if (result.success) {
        console.log(`[Scheduler] \uAC80\uD1A0\uC790 ${result.assignedCount}\uAC1C \uBC30\uC815 \uC644\uB8CC`);
      } else {
        console.error("[Scheduler] \uAC80\uD1A0\uC790 \uBC30\uC815 \uC2E4\uD328");
      }
    } catch (error) {
      console.error("[Scheduler] \uAC80\uD1A0\uC790 \uBC30\uC815 \uC2A4\uCF00\uC904\uB7EC \uC624\uB958:", error);
    }
  });
  console.log("[Scheduler] \uC2B9\uC778 \uC790\uB3D9\uD654 \uC2A4\uCF00\uC904\uB7EC \uCD08\uAE30\uD654 \uC644\uB8CC (\uB9E4\uC77C \uC624\uC804 9\uC2DC/10\uC2DC \uC2E4\uD589)");
}

