// server/schedulers/checklistGenerator.ts
init_db();
init_schema2();
import { CronJob } from "cron";
import { eq as eq110, and as and95 } from "drizzle-orm";
function generatePeriodKey(date16, frequencyType) {
  const year = date16.getFullYear();
  const month = String(date16.getMonth() + 1).padStart(2, "0");
  const day = String(date16.getDate()).padStart(2, "0");
  switch (frequencyType) {
    case "DAILY":
      return `${year}-${month}-${day}`;
    case "WEEKLY": {
      const startOfYear = new Date(year, 0, 1);
      const dayOfYear = Math.floor((date16.getTime() - startOfYear.getTime()) / (24 * 60 * 60 * 1e3));
      const weekNumber = Math.ceil((dayOfYear + startOfYear.getDay() + 1) / 7);
      return `${year}-W${String(weekNumber).padStart(2, "0")}`;
    }
    case "MONTHLY":
      return `${year}-${month}`;
    case "YEARLY":
      return `${year}`;
    default:
      return `${year}-${month}-${day}`;
  }
}
function calculateDueDate(periodKey, dueTime, gracePeriodHours) {
  const date16 = new Date(periodKey);
  if (dueTime) {
    const [hours, minutes] = dueTime.split(":").map(Number);
    date16.setHours(hours, minutes, 0, 0);
  } else {
    date16.setHours(23, 59, 59, 999);
  }
  date16.setHours(date16.getHours() + gracePeriodHours);
  return date16;
}
async function generateInstancesForFrequency(frequencyType, periodKeyFn, dueDateFn) {
  const db2 = await getDb();
  if (!db2) {
    console.error("[\uCCB4\uD06C\uB9AC\uC2A4\uD2B8 \uC0DD\uC131\uAE30] \uB370\uC774\uD130\uBCA0\uC774\uC2A4 \uC5F0\uACB0 \uC2E4\uD328");
    return;
  }
  console.log(`[\uCCB4\uD06C\uB9AC\uC2A4\uD2B8 \uC0DD\uC131\uAE30] ${frequencyType} \uC778\uC2A4\uD134\uC2A4 \uC0DD\uC131 \uC2DC\uC791`);
  try {
    const activeTenants = await db2.select({ id: tenants.id }).from(tenants).where(eq110(tenants.status, "active"));
    const today = /* @__PURE__ */ new Date();
    const periodKey = periodKeyFn(today);
    for (const tenant of activeTenants) {
      const tenantId2 = tenant.id;
      const schedules = await db2.select().from(checklistSchedules).where(
        and95(
          eq110(checklistSchedules.tenantId, tenantId2),
          eq110(checklistSchedules.frequencyType, frequencyType),
          eq110(checklistSchedules.active, 1),
          eq110(checklistSchedules.autoGenerate, 1)
        )
      );
      for (const schedule2 of schedules) {
        const existing = await db2.select().from(checklistInstances).where(
          and95(
            eq110(checklistInstances.tenantId, tenantId2),
            eq110(checklistInstances.templateId, schedule2.templateId),
            eq110(checklistInstances.periodKey, periodKey)
          )
        ).limit(1);
        if (existing[0]) {
          continue;
        }
        const templates = await db2.select().from(checklistTemplates).where(
          and95(
            eq110(checklistTemplates.id, schedule2.templateId),
            eq110(checklistTemplates.tenantId, tenantId2)
          )
        ).limit(1);
        const template = templates[0];
        if (!template) {
          console.error(`[\uCCB4\uD06C\uB9AC\uC2A4\uD2B8 \uC0DD\uC131\uAE30] [tenant:${tenantId2}] \uD15C\uD50C\uB9BF \uC5C6\uC74C: templateId=${schedule2.templateId}`);
          continue;
        }
        const dueDate = dueDateFn(today, schedule2);
        await db2.insert(checklistInstances).values({
          tenantId: tenantId2,
          templateId: schedule2.templateId,
          periodKey,
          dueDate: dueDate.toISOString().replace("T", " ").replace("Z", ""),
          status: "pending",
          createdBy: 0
          // 시스템 생성
        });
        console.log(`[\uCCB4\uD06C\uB9AC\uC2A4\uD2B8 \uC0DD\uC131\uAE30] [tenant:${tenantId2}] \uC0DD\uC131 \uC644\uB8CC: templateId=${schedule2.templateId}, periodKey=${periodKey}`);
      }
    }
    console.log(`[\uCCB4\uD06C\uB9AC\uC2A4\uD2B8 \uC0DD\uC131\uAE30] ${frequencyType} \uC778\uC2A4\uD134\uC2A4 \uC0DD\uC131 \uC644\uB8CC`);
  } catch (error) {
    console.error(`[\uCCB4\uD06C\uB9AC\uC2A4\uD2B8 \uC0DD\uC131\uAE30] ${frequencyType} \uC778\uC2A4\uD134\uC2A4 \uC0DD\uC131 \uC624\uB958:`, error);
  }
}
async function generateDailyInstances() {
  await generateInstancesForFrequency(
    "DAILY",
    (today) => generatePeriodKey(today, "DAILY"),
    (today, schedule2) => calculateDueDate(generatePeriodKey(today, "DAILY"), schedule2.dueTime, Number(schedule2.gracePeriodHours))
  );
}
async function generateWeeklyInstances() {
  await generateInstancesForFrequency(
    "WEEKLY",
    (today) => generatePeriodKey(today, "WEEKLY"),
    (today, schedule2) => {
      const endOfWeek = new Date(today);
      endOfWeek.setDate(endOfWeek.getDate() + (7 - endOfWeek.getDay()));
      return calculateDueDate(endOfWeek.toISOString().split("T")[0], schedule2.dueTime, Number(schedule2.gracePeriodHours));
    }
  );
}
async function generateMonthlyInstances() {
  await generateInstancesForFrequency(
    "MONTHLY",
    (today) => generatePeriodKey(today, "MONTHLY"),
    (today, schedule2) => {
      const endOfMonth = new Date(today.getFullYear(), today.getMonth() + 1, 0);
      return calculateDueDate(endOfMonth.toISOString().split("T")[0], schedule2.dueTime, Number(schedule2.gracePeriodHours));
    }
  );
}
function initChecklistGenerator() {
  new CronJob(
    "0 6 * * *",
    generateDailyInstances,
    null,
    true,
    "Asia/Seoul"
  );
  new CronJob(
    "0 6 * * 1",
    generateWeeklyInstances,
    null,
    true,
    "Asia/Seoul"
  );
  new CronJob(
    "0 6 1 * *",
    generateMonthlyInstances,
    null,
    true,
    "Asia/Seoul"
  );
  console.log("[\uCCB4\uD06C\uB9AC\uC2A4\uD2B8 \uC0DD\uC131\uAE30] \uC2A4\uCF00\uC904\uB7EC \uCD08\uAE30\uD654 \uC644\uB8CC");
}

// server/services/subscriptionScheduler.ts
init_db();
init_schema_main();
import { eq as eq111, and as and96, gte as gte46, sql as sql65 } from "drizzle-orm";
async function checkSubscriptionExpiry() {
  console.log("[Subscription Scheduler] Starting subscription expiry check...");
  try {
    const today = /* @__PURE__ */ new Date();
    today.setHours(0, 0, 0, 0);
    const db2 = await getDb();
    const activeTenants = await db2.select().from(tenants).where(sql65`${tenants.status} IN ('active', 'trial')`);
    console.log(`[Subscription Scheduler] Found ${activeTenants.length} active tenants`);
    for (const tenant of activeTenants) {
      if (!tenant.subscriptionEndDate) {
        continue;
      }
      const endDate = new Date(tenant.subscriptionEndDate);
      endDate.setHours(0, 0, 0, 0);
      const diffTime = endDate.getTime() - today.getTime();
      const daysRemaining = Math.ceil(diffTime / (1e3 * 60 * 60 * 24));
      console.log(`[Subscription Scheduler] Tenant ${tenant.name} (ID: ${tenant.id}): ${daysRemaining} days remaining`);
      if (daysRemaining === 7) {
        await sendNotification(
          tenant.id,
          "7_days",
          `\uAD6C\uB3C5\uC774 7\uC77C \uD6C4 \uB9CC\uB8CC\uB429\uB2C8\uB2E4. \uAD6C\uB3C5\uC744 \uC5F0\uC7A5\uD574\uC8FC\uC138\uC694.`
        );
      }
      if (daysRemaining === 3) {
        await sendNotification(
          tenant.id,
          "3_days",
          `\uAD6C\uB3C5\uC774 3\uC77C \uD6C4 \uB9CC\uB8CC\uB429\uB2C8\uB2E4. \uAD6C\uB3C5\uC744 \uC5F0\uC7A5\uD574\uC8FC\uC138\uC694.`
        );
      }
      if (daysRemaining === 1) {
        await sendNotification(
          tenant.id,
          "1_day",
          `\uAD6C\uB3C5\uC774 \uB0B4\uC77C \uB9CC\uB8CC\uB429\uB2C8\uB2E4. \uAD6C\uB3C5\uC744 \uC5F0\uC7A5\uD574\uC8FC\uC138\uC694.`
        );
      }
      if (daysRemaining === 0) {
        const gracePeriodEnd = new Date(endDate);
        gracePeriodEnd.setDate(gracePeriodEnd.getDate() + 7);
        await db2.update(tenants).set({
          status: "expired",
          isReadOnly: true,
          gracePeriodEndDate: gracePeriodEnd.toISOString().split("T")[0]
        }).where(eq111(tenants.id, tenant.id));
        await sendNotification(
          tenant.id,
          "expired",
          `\uAD6C\uB3C5\uC774 \uB9CC\uB8CC\uB418\uC5C8\uC2B5\uB2C8\uB2E4. 7\uC77C \uC720\uC608\uAE30\uAC04 \uB3D9\uC548 \uC77D\uAE30 \uC804\uC6A9 \uBAA8\uB4DC\uB85C \uC804\uD658\uB429\uB2C8\uB2E4. \uAD6C\uB3C5\uC744 \uC5F0\uC7A5\uD574\uC8FC\uC138\uC694.`
        );
        console.log(`[Subscription Scheduler] Tenant ${tenant.name} (ID: ${tenant.id}) expired, grace period until ${gracePeriodEnd.toISOString().split("T")[0]}`);
      }
      if (tenant.gracePeriodEndDate) {
        const gracePeriodEnd = new Date(tenant.gracePeriodEndDate);
        gracePeriodEnd.setHours(0, 0, 0, 0);
        const graceDiffTime = gracePeriodEnd.getTime() - today.getTime();
        const graceDaysRemaining = Math.ceil(graceDiffTime / (1e3 * 60 * 60 * 24));
        if (graceDaysRemaining === 0 && tenant.status === "expired") {
          await db2.update(tenants).set({
            status: "suspended"
          }).where(eq111(tenants.id, tenant.id));
          await sendNotification(
            tenant.id,
            "grace_period_end",
            `\uC720\uC608\uAE30\uAC04\uC774 \uC885\uB8CC\uB418\uC5C8\uC2B5\uB2C8\uB2E4. \uC11C\uBE44\uC2A4 \uC774\uC6A9\uC774 \uC911\uB2E8\uB418\uC5C8\uC2B5\uB2C8\uB2E4. \uAD6C\uB3C5\uC744 \uC5F0\uC7A5\uD574\uC8FC\uC138\uC694.`
          );
          console.log(`[Subscription Scheduler] Tenant ${tenant.name} (ID: ${tenant.id}) suspended after grace period`);
        }
      }
    }
    console.log("[Subscription Scheduler] Subscription expiry check completed");
  } catch (error) {
    console.error("[Subscription Scheduler] Error checking subscription expiry:", error);
    throw error;
  }
}
async function sendNotification(tenantId2, type, message) {
  try {
    const db2 = await getDb();
    const today = /* @__PURE__ */ new Date();
    today.setHours(0, 0, 0, 0);
    const existingNotifications = await db2.select().from(subscriptionNotifications).where(
      and96(
        eq111(subscriptionNotifications.tenantId, tenantId2),
        eq111(subscriptionNotifications.notificationType, type),
        gte46(subscriptionNotifications.notificationDate, today)
      )
    ).limit(1);
    const existingNotification = existingNotifications[0];
    if (existingNotification) {
      console.log(`[Subscription Scheduler] Notification already sent for tenant ${tenantId2}, type ${type}`);
      return;
    }
    await db2.insert(subscriptionNotifications).values({
      tenantId: tenantId2,
      notificationType: type,
      message,
      isRead: false
    });
    console.log(`[Subscription Scheduler] Notification sent to tenant ${tenantId2}: ${type}`);
  } catch (error) {
    console.error(`[Subscription Scheduler] Error sending notification to tenant ${tenantId2}:`, error);
  }
}
function initSubscriptionScheduler() {
  console.log("[Subscription Scheduler] Initializing subscription scheduler...");
  checkSubscriptionExpiry().catch(console.error);
  setInterval(() => {
    checkSubscriptionExpiry().catch(console.error);
  }, 24 * 60 * 60 * 1e3);
  console.log("[Subscription Scheduler] Subscription scheduler initialized");
}

// server/_core/index.ts
init_dailyClosingScheduler();
function isPortAvailable(port) {
  return new Promise((resolve) => {
    const server = net.createServer();
    server.listen(port, () => {
      server.close(() => resolve(true));
    });
    server.on("error", () => resolve(false));
  });
}
async function findAvailablePort(startPort = 3e3) {
  for (let port = startPort; port < startPort + 20; port++) {
    if (await isPortAvailable(port)) {
      return port;
    }
  }
  throw new Error(`No available port found starting from ${startPort}`);
}
async function startServer() {
  const app = express2();
  const server = createServer(app);
  app.use(cors({
    origin: true,
    // 모든 origin 허용 (개발 환경)
    credentials: true
    // 쿠키 전송 허용
  }));
  app.use(express2.json({ limit: "50mb" }));
  app.use(express2.urlencoded({ limit: "50mb", extended: true }));
  app.use(cookieParser());
  const redisClient = createClient({
    url: process.env.REDIS_URL || "redis://localhost:6379",
    socket: {
      reconnectStrategy: (retries) => {
        if (retries > 10) {
          console.error("[Redis] Max reconnection attempts reached. Giving up.");
          return new Error("Max reconnection attempts reached");
        }
        const delay = Math.min(retries * 100, 3e3);
        console.log(`[Redis] Reconnecting in ${delay}ms... (attempt ${retries})`);
        return delay;
      }
    }
  });
  redisClient.on("error", (err) => {
    console.error("[Redis] Client error:", err.message);
  });
  redisClient.on("connect", () => {
    console.log("[Redis] Connected successfully");
  });
  redisClient.on("reconnecting", () => {
    console.log("[Redis] Reconnecting...");
  });
  try {
    await redisClient.connect();
    console.log("[Redis] Session store ready");
  } catch (err) {
    console.error("[Redis] Failed to connect:", err);
    console.warn("[Redis] Falling back to MemoryStore (NOT recommended for production)");
  }
  const redisStore = new RedisStore({
    client: redisClient,
    prefix: "haccp:sess:",
    // 세션 키 접두사
    ttl: 60 * 60 * 24 * 7
    // 7일 (초 단위)
  });
  app.use(session({
    store: redisStore,
    secret: process.env.SESSION_SECRET || "haccp-v3-session-secret-key-change-in-production",
    resave: false,
    saveUninitialized: false,
    cookie: {
      httpOnly: true,
      secure: process.env.NODE_ENV === "production",
      // HTTPS에서만 secure 쿠키
      sameSite: "lax",
      maxAge: 1e3 * 60 * 60 * 24 * 7,
      // 7일
      domain: process.env.NODE_ENV === "production" ? ".haccpone.co.kr" : void 0
    }
  }));
  app.use(loginRouter);
  const customPeriodLogRouter = (await Promise.resolve().then(() => (init_customPeriodLogs(), customPeriodLogs_exports))).default;
  app.use("/api/customPeriodLog", customPeriodLogRouter);
  const yearlyLogRestRouter = (await Promise.resolve().then(() => (init_yearlyLogRest(), yearlyLogRest_exports))).default;
  app.use("/api/yearlyLog", yearlyLogRestRouter);
  app.use("/api/superadmin", superadmin_default);
  app.use(
    "/api/trpc",
    createExpressMiddleware({
      router: appRouter,
      createContext
    })
  );
  if (process.env.NODE_ENV === "development") {
    await setupVite(app, server);
  } else {
    serveStatic(app);
  }
  const preferredPort = parseInt(process.env.PORT || "3000");
  const port = await findAvailablePort(preferredPort);
  if (port !== preferredPort) {
    console.log(`Port ${preferredPort} is busy, using port ${port} instead`);
  }
  server.listen(port, "0.0.0.0", () => {
    console.log(`Server running on http://0.0.0.0:${port}/`);
    initScheduler();
    console.log("[Scheduler] \uBAA8\uB4E0 \uC2A4\uCF00\uC904\uB7EC \uC784\uC2DC \uBE44\uD65C\uC131\uD654 (\uB85C\uADF8\uC778 \uAE30\uB2A5 \uC548\uC815\uD654\uB97C \uC704\uD574)");
    initApprovalAutomationScheduler();
    initChecklistGenerator();
    initInspectionReportScheduler();
    initSubscriptionScheduler();
    initDailyClosingScheduler();
  });
  const gracefulShutdown = async () => {
    console.log("[Server] Shutting down gracefully...");
    try {
      await redisClient.quit();
      console.log("[Redis] Disconnected");
    } catch (err) {
      console.error("[Redis] Error during disconnect:", err);
    }
    server.close(() => {
      console.log("[Server] Closed");
      process.exit(0);
    });
  };
  process.on("SIGTERM", gracefulShutdown);
  process.on("SIGINT", gracefulShutdown);
}
startServer().catch(console.error);
